(function($){let settings=[];let setting={};let table;$.fn.table=function(options,params){if(typeof options==="object"){table=$(this);var currentId=table.attr("id");var instance={id:currentId,endpoint:"",type:"GET",mappingFunction:function(data){return""},success:function(e,data){return},fail:function(error){return},messageNoResult:"No records returned",messageErrorOccured:"Error occurred",messageNotFound:"Data not found",cssClassNoResult:"text-center",messageLoading:"Loading data...",params:{},data:[],refresh:refresh,sortKey:null,sortType:null,async:true};setting=$.extend(true,instance,options);settings.push(setting);refresh();return table}if(typeof options==="string"){table=$(this);var currentId=table.attr("id");if(options=="refresh"){var foundSettings=$.grep(settings,(function(e){return e.id==currentId}));var foundSetting=foundSettings[0];if(params!=undefined)foundSetting.params=params;if(foundSettings.length>0){setting=$.extend(true,foundSettings[0],options);settings.push(setting);refresh();return table}}if(options=="load"){var foundSettings=$.grep(settings,(function(e){return e.id==currentId}));var foundSetting=foundSettings[0];if(params!=undefined)foundSetting.data=params;if(foundSettings.length>0){setting=$.extend(true,foundSettings[0],options);settings.push(setting);load();return table}}if(options=="clear"){table.find("tbody").empty()}}return table};function refresh(){generateTableBody(null,0);var parameters={context:document.body,dataType:"json",async:setting.async,statusCode:{404:function(data){generateTableBody(data,404)},500:function(data){generateTableBody(data,500)},200:function(data){generateTableBody(data,200)}},complete:function(data){setting.success()}};if(setting.type.toUpperCase()=="GET"){var queryString="";try{queryString=jQuery.param(setting.params)}catch(exception){queryString=""}parameters.url=setting.endpoint+"?"+queryString}else if(setting.type.toUpperCase()=="POST"){parameters.url=setting.endpoint;parameters.data=setting.params}else{setting.fail("Unsupported call type");return}$.ajax(parameters)}function load(){generateTableBody(setting.data,200);setting.success()}function generateTableBody(data,code){var html="";var tbody=table.find("tbody");tbody.find("tr").remove();if(code==0){html=`<tr>\n                       <td colspan="${getColspan(table)}" class="busy ${setting.cssClassNoResult}"><strong>${setting.messageLoading}</strong></td>\n                   </tr>`}if(code==404){html=`<tr>\n                       <td colspan="${getColspan(table)}" class="${setting.cssClassNoResult}">${setting.messageNotFound}</td>\n                   </tr>`}if(code==500){html=`<tr>\n                       <td colspan="${getColspan(table)}" class="${setting.cssClassNoResult}">${setting.messageErrorOccured}</td>\n                   </tr>`}if(code==200){try{html=setting.mappingFunction(data)}catch(exception){html=""}if(html==""){html=`<tr>\n                           <td colspan="${getColspan(table)}" class="${setting.cssClassNoResult}"><strong>${setting.messageNoResult}</strong></td>\n                       </tr>`}}tbody.html(html)}function getColspan(table){var colspan=1;table.find("thead > tr:nth-child(1) th").each((function(){if($(this).attr("colspan")){colspan+=+$(this).attr("colspan")}else{colspan++}}));return colspan}function sort(){if(setting.sortKey==null)return;var col=setting.sortKey;var reverse=setting.sortType=="asc"?1:-1;var table=document.getElementById(setting.id);var tb=table.tBodies[0],tr=Array.prototype.slice.call(tb.rows,0),i;tr=tr.sort((function(a,b){return reverse*a.cells[col].textContent.trim().localeCompare(b.cells[col].textContent.trim())}));for(i=0;i<tr.length;++i)tb.appendChild(tr[i])}})(jQuery);